// src/pages/PrintMovimentacoes.jsx

import React, { useEffect, useState } from 'react'
import { useLocation, useNavigate } from 'react-router-dom'
import axios from 'axios'

export default function PrintMovimentacoes() {
  const { state: filters } = useLocation()
  const navigate = useNavigate()
  const [lista, setLista] = useState([])

  // 1) Busca as movimentações já filtradas
  useEffect(() => {
    axios.get('/api/movimentacoes', { params: filters })
      .then(res => setLista(res.data))
      .catch(console.error)
  }, [filters])

  // 2) Assim que carregar a lista, dispara a impressão e, ao fechar,
  //    garante que voltamos para a tela de esterilização
  useEffect(() => {
    if (!lista.length) return

    const goBack = () => {
      // substitui a rota atual por /esterilizacao
      navigate('/esterilizacao', { replace: true })
    }

    // para navegadores que suportam afterprint
    window.addEventListener('afterprint', goBack)
    // fallback para quando o foco retorna à aba
    window.addEventListener('focus', goBack)

    // dispara o diálogo de impressão na próxima iteração
    setTimeout(() => window.print(), 0)

    return () => {
      window.removeEventListener('afterprint', goBack)
      window.removeEventListener('focus', goBack)
    }
  }, [lista, navigate])

  return (
    <div className="p-4">
      <h1 className="text-xl font-semibold mb-4">Movimentações Filtradas</h1>
      <table className="w-full border-collapse">
        <thead>
          <tr className="bg-gray-200">
            <th className="border px-2 py-1 text-left">Tipo</th>
            <th className="border px-2 py-1 text-left">Caixa</th>
            <th className="border px-2 py-1 text-left">Aluno</th>
            <th className="border px-2 py-1 text-left">Período</th>
            <th className="border px-2 py-1 text-left">Data</th>
            <th className="border px-2 py-1 text-left">Operador</th>
          </tr>
        </thead>
        <tbody>
          {lista.map(m => (
            <tr key={m.id}>
              <td className="border px-2 py-1">{m.tipo}</td>
              <td className="border px-2 py-1">{m.caixaNome}</td>
              <td className="border px-2 py-1">{m.alunoNome}</td>
              <td className="border px-2 py-1">{m.periodoNome}</td>
              <td className="border px-2 py-1">{m.criado_em}</td>
              <td className="border px-2 py-1">{m.operadorNome}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}
